import {useEffect, useRef} from 'react';
import type {TextInput} from 'react-native';
import {useKeyboardNav} from './useKeyboardNavigation';

/**
 * Convenience hook for native text input molecules.
 * Creates a local TextInput ref, registers it in the KeyboardNavContext,
 * and returns the ref + navigation props to spread on the InputField.
 */
export function useFormFieldKeyboardNav(id: string | undefined) {
    const inputRef = useRef<TextInput>(null);
    const nav = useKeyboardNav();

    useEffect(() => {
        if (!id || !nav) return;
        nav.register(id, inputRef);
        return () => nav.unregister(id);
    }, [id, nav]);

    const navProps = id && nav ? nav.getNavProps(id) : {};
    const focusNext = id && nav ? () => nav.focusNext(id) : undefined;

    return {inputRef, navProps, focusNext};
}
